const clickupRaw = $('Fetch ClickUp Tasks').first().json;
const clickupTasks = clickupRaw.tasks || [];
const dbTickets = $('Merge DB Tickets').first().json._db_tickets;
const merged = $('Merge Configs').first().json;
const solutionConfig = merged._solution_config;
const slaConfigs = merged._sla_configs;

const dbMap = {};
for (const t of dbTickets) {
  if (t.clickup_task_id) dbMap[t.clickup_task_id] = t;
}
const clickupIds = new Set(clickupTasks.map(t => t.id));
const results = [];

// Status groups
const CLOSED_STATUSES = ['closed', 'resolved', 'complete', 'rejected', 'done'];
const PAUSED_STATUSES = ['on hold', 'blocked', 'on_hold'];

for (const task of clickupTasks) {
  const existing = dbMap[task.id];

  // Extract custom fields as name→value map
  const customFields = {};
  if (task.custom_fields) {
    for (const cf of task.custom_fields) {
      const fieldName = cf.name?.toLowerCase()?.replace(/\s+/g, '_');
      let fieldValue = null;
      if (cf.type === 'drop_down' && cf.type_config?.options && cf.value !== undefined && cf.value !== null) {
        const option = cf.type_config.options.find(o => o.orderindex === cf.value);
        fieldValue = option?.name || null;
      } else if (cf.type === 'number') {
        fieldValue = cf.value != null ? String(cf.value) : null;
      } else {
        fieldValue = cf.value || null;
      }
      if (fieldName) customFields[fieldName] = fieldValue;
    }
  }

  // Priority mapping: ClickUp → P1-P5
  let priority = 'P3';
  if (task.priority) {
    const pMap = { 'urgent': 'P1', 'high': 'P2', 'normal': 'P3', 'low': 'P4' };
    priority = pMap[task.priority?.priority?.toLowerCase()] || 'P3';
  } else {
    priority = 'P5'; // No priority = Very Low
  }

  const statusRaw = task.status?.status || 'open';
  const statusLower = statusRaw.toLowerCase();

  const taskData = {
    clickup_task_id: task.id,
    clickup_url: task.url,
    title: task.name || 'Untitled',
    description: (task.description || '').substring(0, 5000),
    status: statusRaw,
    status_type: task.status?.type || null,
    priority: priority,
    _is_closed_status: CLOSED_STATUSES.includes(statusLower),
    _is_paused_status: PAUSED_STATUSES.includes(statusLower),
    module: customFields.module || null,
    operating_system: customFields.operating_system || null,
    mobile_or_national_id: customFields.patient_identifier || null,
    request_type_clickup: customFields.request_type || null,
    case_type_clickup: customFields.case_type || null,
    created_at: task.date_created ? new Date(parseInt(task.date_created)).toISOString() : new Date().toISOString(),
    updated_at: task.date_updated ? new Date(parseInt(task.date_updated)).toISOString() : new Date().toISOString(),
    closed_at: task.date_closed ? new Date(parseInt(task.date_closed)).toISOString() : null,
    created_by_email: task.creator?.email || null,
    created_by_name: task.creator?.username || null,
    assignees: task.assignees || [],
    tags: task.tags?.map(tg => tg.name) || [],
    custom_fields: customFields,
    _solution_id: solutionConfig.solution_id,
    _company_id: solutionConfig.company_id,
    _company_domain: solutionConfig.domain,
    _sla_configs: slaConfigs,
    _solution_config: solutionConfig
  };

  if (!existing) {
    results.push({ json: { ...taskData, _sync_action: 'NEW' } });
  } else {
    const changes = [];
    if (existing.status?.toLowerCase() !== statusLower) changes.push('status');
    if (existing.priority !== taskData.priority) changes.push('priority');
    if (existing.title !== taskData.title) changes.push('title');
    const exUp = existing.updated_at ? new Date(existing.updated_at).getTime() : 0;
    const cuUp = new Date(taskData.updated_at).getTime();
    if (cuUp > exUp) changes.push('updated_at');

    results.push({
      json: {
        ...taskData,
        _sync_action: 'EXISTS',
        _db_ticket_id: existing.ticket_id,
        _has_changes: changes.length > 0,
        _changed_fields: changes,
        _existing_thread_ids: existing.existing_thread_ids || [],
        _existing_priority: existing.priority,
        _existing_sla_status: existing.sla_status,
        _existing_escalation_level: existing.escalation_level,
        _existing_sla_consumption_pct: existing.sla_consumption_pct,
        _existing_sla_response_due: existing.sla_response_due,
        _existing_sla_resolution_due: existing.sla_resolution_due,
        _existing_sla_paused_at: existing.sla_paused_at,
        _existing_sla_paused_duration: existing.sla_paused_duration
      }
    });
  }
}

// Deleted tickets
for (const db of dbTickets) {
  if (db.clickup_task_id && !clickupIds.has(db.clickup_task_id)) {
    results.push({
      json: {
        _sync_action: 'DELETED',
        _db_ticket_id: db.ticket_id,
        clickup_task_id: db.clickup_task_id,
        title: db.title
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { _sync_action: 'NONE', message: 'No tickets to process' } }];
}
return results;

const ticket = $('Route by Action').first().json;
const pocResult = $input.first().json;

let pocId = pocResult?.poc_id || null;
let pocAction = pocId ? 'EXISTING' : 'CREATE';

return [{
  json: {
    ...ticket,
    _poc_id: pocId,
    _poc_action: pocAction,
    _poc_type: pocId ? 'known' : 'pending' // resolved after Create POC
  }
}];

// Merge POC ID back into ticket data
const ticket = $('Evaluate POC').first().json;
const pocAction = ticket._poc_action;

let pocId;
if (pocAction === 'CREATE') {
  pocId = $('Create POC').first().json.poc_id;
} else {
  pocId = ticket._poc_id;
}

return [{
  json: {
    ...ticket,
    _poc_id: pocId
  }
}];

// ===== BUILD LLM PROFILING REQUEST =====
const ticket = $input.first().json;
const modules = ['Login/Sign Up','Language','Landing Page (Home)','My Health','Cash Claims','Call Doctor Now','Appointment','AI Companion','Apps Sections and Functions','Digital Twin','Wellness'];

const systemPrompt = `You are an expert support ticket classifier for MedGulf healthcare mobile app.

Your job is to analyze a new support ticket and return a structured JSON profile.

Available modules: ${modules.join(', ')}

Request types:
- Incident: Unplanned interruption or quality reduction of a service
- Service Request: User guidance, configuration change, or access request
- Problem: Recurring incident needing root cause investigation
- Change Request: New feature or enhancement request

Priority levels (assess based on impact and urgency):
- P1 (Critical): Complete system/app outage or total loss of service
- P2 (High): Major functionality impaired, core operations impacted
- P3 (Medium): Partial disruption affecting non-core functions
- P4 (Low): Minor issue with limited impact
- P5 (Very Low): Isolated issue with minimal impact

Respond ONLY with valid JSON, no markdown, no explanation:
{
  "request_type": "Incident|Service Request|Problem|Change Request",
  "case_type": "<brief case type label, e.g. 'Login Failure', 'Crash on Launch'>",
  "priority": "P1|P2|P3|P4|P5",
  "sentiment": "positive|neutral|negative|frustrated|angry",
  "summary": "<1-2 sentence summary of the issue>",
  "module": "<best matching module from the list, or 'Unknown'>"
}`;

const userMessage = `Ticket Title: ${ticket.title}\n\nDescription:\n${ticket.description || 'No description provided'}\n\nReported Module: ${ticket.module || 'Not specified'}\nReporter: ${ticket.created_by_name || 'Unknown'}\nTags: ${(ticket.tags || []).join(', ') || 'None'}`;

const requestBody = {
  temperature: 0.1,
  model: 'gpt-4o',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

return [{
  json: {
    requestBody: JSON.stringify(requestBody),
    _ticket: ticket
  }
}];

const llmResponse = $input.first().json;
const ticket = $('Build LLM Profile Request').first().json._ticket;

let profile;
try {
  const content = llmResponse.choices?.[0]?.message?.content || '{}';
  const cleaned = content.replace(/```json|```/g, '').trim();
  profile = JSON.parse(cleaned);
} catch (e) {
  profile = {
    request_type: ticket.request_type_clickup || 'Incident',
    case_type: 'Uncategorized',
    priority: ticket.priority || 'P3',
    sentiment: 'neutral',
    summary: ticket.title,
    module: ticket.module || 'Unknown'
  };
}

const finalPriority = profile.priority || ticket.priority || 'P3';

// SLA applicability: only Incidents and Problems
const requestType = profile.request_type || ticket.request_type_clickup || 'Incident';
const isSlaApplicable = ['Incident', 'Problem'].includes(requestType);

const slaConfigs = ticket._sla_configs || [];
const slaConfig = isSlaApplicable ? slaConfigs.find(s => s.priority === finalPriority) : null;
const hasHourSla = slaConfig && slaConfig.resolution_type === 'hours' && slaConfig.resolution_hours;

const cfg = ticket._solution_config || {};
const bhS = parseInt((cfg.business_hours_start || '08:00').split(':')[0]);
const bhE = parseInt((cfg.business_hours_end || '20:00').split(':')[0]);

function addBH(startDate, hours) {
  if (!hours || hours <= 0) return null;
  let cur = new Date(startDate);
  let rem = hours;
  for (let i = 0; i < 500 && rem > 0; i++) {
    const dh = cur.getUTCHours() + 4;
    const ah = dh >= 24 ? dh - 24 : dh;
    if (ah >= bhS && ah < bhE) {
      const left = bhE - ah;
      const c = Math.min(rem, left);
      rem -= c;
      cur = new Date(cur.getTime() + c * 3600000);
    } else if (ah < bhS) {
      cur = new Date(cur.getTime() + (bhS - ah) * 3600000);
    } else {
      cur = new Date(cur.getTime() + ((24 - ah) + bhS) * 3600000);
    }
  }
  return cur.toISOString();
}

const now = new Date();
const slaRespDue = isSlaApplicable && slaConfig?.response_hours ? addBH(now, slaConfig.response_hours) : null;
const slaResDue = hasHourSla ? addBH(now, slaConfig.resolution_hours) : null;

return [{
  json: {
    ...ticket,
    request_type: requestType,
    case_type: profile.case_type,
    priority: finalPriority,
    ai_sentiment: profile.sentiment,
    ai_summary: profile.summary,
    module: profile.module !== 'Unknown' ? profile.module : ticket.module,
    sla_applicable: isSlaApplicable,
    sla_response_due: slaRespDue,
    sla_resolution_due: slaResDue,
    sla_status: isSlaApplicable ? 'healthy' : 'not_applicable',
    sla_consumption_pct: 0,
    escalation_level: 0
  }
}];

// Insert the initial thread (ticket creation event)
const insertResult = $('Insert New Ticket').first().json;
const ticketData = $('Parse LLM + Calculate SLA').first().json;

return [{
  json: {
    ticket_id: insertResult.ticket_id,
    action_type: 'ticket_created',
    actor_email: ticketData.created_by_email,
    actor_name: ticketData.created_by_name,
    raw_content: ticketData.description || ticketData.title,
    ai_summary: ticketData.ai_summary,
    created_at: ticketData.created_at
  }
}];

const ticket = $('Route by Action').first().json;
const commentsRaw = $input.first().json;
const comments = commentsRaw.comments || [];

const existingThreadIds = ticket._existing_thread_ids || [];
const existingIdSet = new Set(existingThreadIds.map(String));
const newComments = comments.filter(c => !existingIdSet.has(String(c.id)));

const changes = ticket._changed_fields || [];
const hasNewComments = newComments.length > 0;
const hasFieldChanges = changes.length > 0;

// SLA impact detection
let slaImpact = 'none';
const statusLower = ticket.status?.toLowerCase();

if (changes.includes('status')) {
  if (['on hold', 'blocked', 'on_hold'].includes(statusLower)) {
    slaImpact = 'pause';
  } else if (['open', 'in progress', 'in_progress', 'active'].includes(statusLower)) {
    slaImpact = 'resume';
  } else if (['closed', 'resolved', 'complete', 'rejected', 'done'].includes(statusLower)) {
    slaImpact = 'stop';
  }
}

// Priority change with DIRECTION
let priorityChangeDirection = null;
if (changes.includes('priority')) {
  const pRank = { 'P1': 1, 'P2': 2, 'P3': 3, 'P4': 4, 'P5': 5 };
  const oldR = pRank[ticket._existing_priority] || 3;
  const newR = pRank[ticket.priority] || 3;
  if (newR < oldR) {
    priorityChangeDirection = 'upgrade';
    slaImpact = 'priority_upgrade';
  } else if (newR > oldR) {
    priorityChangeDirection = 'downgrade';
    slaImpact = 'priority_downgrade';
  }
}

return [{
  json: {
    ...ticket,
    _new_comments: newComments,
    _has_new_comments: hasNewComments,
    _has_field_changes: hasFieldChanges,
    _has_any_changes: hasNewComments || hasFieldChanges,
    _sla_impact: slaImpact,
    _priority_change_direction: priorityChangeDirection,
    _all_comment_ids: comments.map(c => String(c.id))
  }
}];

// ─── THREAD COMPACTION (run-length encoding for consecutive duplicates) ───────

function getSignature(t) {
  return `${t.action_type}|${String(t.raw_content).trim()}|${String(t.new_value).trim()}`;
}

function compactThreads(threads) {
  const compacted = [];
  let i = 0;

  while (i < threads.length) {
    const current = threads[i];
    const sig = getSignature(current);
    let count = 1;
    let j = i + 1;

    while (j < threads.length && getSignature(threads[j]) === sig) {
      count++;
      j++;
    }

    if (count > 1) {
      const last = threads[j - 1];
      const firstTime = new Date(current.created_at).toISOString().replace('T', ' ').substring(0, 16);
      const lastTime  = new Date(last.created_at).toISOString().replace('T', ' ').substring(0, 16);

      compacted.push({
        id: current.id,
        action_type: current.action_type,
        actor_name: current.actor_name,
        actor_email: current.actor_email,
        old_value: current.old_value,
        new_value: current.new_value,
        raw_content: current.raw_content,
        ai_summary: current.ai_summary || current.raw_content,
        created_at: current.created_at,
        thread_source: current.thread_source,
        metadata: current.metadata,
        _collapsed: true,
        _count: count,
        _first_at: current.created_at,
        _last_at: last.created_at,
        _collapse_note: `↻ Repeated ×${count} (${firstTime} → ${lastTime})`
      });
    } else {
      compacted.push({ ...current, _collapsed: false, _count: 1 });
    }

    i = j;
  }

  return compacted;
}

function deduplicateSlaComments(threads) {
  const toRemove = new Set();

  threads.forEach((t, idx) => {
    if (t.action_type !== 'comment') return;
    if (!t.raw_content || !t.raw_content.includes('SLA ESCALATION')) return;

    const tTime = new Date(t.created_at).getTime();
    const window = threads.slice(Math.max(0, idx - 3), Math.min(threads.length, idx + 4));
    const hasPair = window.some(w =>
      w.id !== t.id &&
      w.action_type === 'sla_escalation' &&
      Math.abs(new Date(w.created_at).getTime() - tTime) <= 5000
    );

    if (hasPair) toRemove.add(t.id);
  });

  return threads.filter(t => !toRemove.has(t.id));
}

function buildEntry(t) {
  const time = new Date(t.created_at).toISOString().replace('T', ' ').substring(0, 16) + 'Z';
  const actor = t.actor_name || t.actor_email || 'system';
  const collapseNote = t._collapsed ? `  ${t._collapse_note}` : '';

  switch (t.action_type) {
    case 'ticket_created':
      return `[${time}] CREATED by ${actor}\n  ${(t.ai_summary || t.raw_content || '').substring(0, 600)}`;

    case 'field_change': {
      let details = t.raw_content || '';
      try {
        const nv = typeof t.new_value === 'string' ? JSON.parse(t.new_value) : t.new_value;
        if (nv && typeof nv === 'object') {
          details = 'Changed: ' + Object.entries(nv).map(([k, v]) => `${k}=${v}`).join(', ')
                  + (t.raw_content ? ` | ${t.raw_content}` : '');
        }
      } catch (_) {}
      return `[${time}] FIELD CHANGE by ${actor}: ${details.substring(0, 200)}${collapseNote}`;
    }

    case 'comment':
      return `[${time}] COMMENT by ${actor}:\n  ${(t.raw_content || '').substring(0, 400)}`;

    case 'sla_escalation': {
      const pct = t.metadata?.pct ?? 'N/A';
      const lvl = t.metadata?.level ?? '?';
      return `[${time}] SLA ESCALATION E${lvl} at ${pct}% by ${actor}: ${(t.ai_summary || t.raw_content || '').substring(0, 200)}`;
    }

    case 'status_change':
      return `[${time}] STATUS CHANGE by ${actor}: ${t.old_value || '?'} → ${t.new_value || '?'}${collapseNote}`;

    case 'assignment':
      return `[${time}] ASSIGNED by ${actor}: ${(t.raw_content || '').substring(0, 200)}`;

    case 'priority_change':
      return `[${time}] PRIORITY CHANGE by ${actor}: ${t.old_value || '?'} → ${t.new_value || '?'}`;

    case 'resolution':
      return `[${time}] RESOLVED by ${actor}: ${(t.ai_summary || t.raw_content || '').substring(0, 300)}`;

    default:
      return `[${time}] ${t.action_type.toUpperCase()} by ${actor}: ${(t.ai_summary || t.raw_content || '').substring(0, 200)}${collapseNote}`;
  }
}

// ─── MAIN ─────────────────────────────────────────────────────────────────────
const ticket = $('Detect Changes').first().json;  // ← original ticket with all fields
const rawThreads = $input.all().map(i => i.json); // ← thread rows from Fetch All Threads

const ticketData = ticket;
const slaData    = {};
const escalations = [];

// ─── RUN COMPACTION ───────────────────────────────────────────────────────────
const dedupedThreads   = deduplicateSlaComments(rawThreads);
const compactedThreads = compactThreads(dedupedThreads);
const timelineLines    = compactedThreads.map(buildEntry).filter(Boolean);

// ─── Stats ────────────────────────────────────────────────────────────────────
const originalCount  = rawThreads.length;
const compactedCount = compactedThreads.length;
const reductionPct   = originalCount > 0
  ? Math.round((1 - compactedCount / originalCount) * 100)
  : 0;

const slaEscalations = compactedThreads.filter(t => t.action_type === 'sla_escalation');
const escalationSummary = slaEscalations.length > 0
  ? slaEscalations.map(e => `E${e.metadata?.level} @ ${e.metadata?.pct}%`).join(' → ')
  : 'None';

// ─── Prompts ──────────────────────────────────────────────────────────────────
const systemPrompt = `You are a technical support analyst summarizing ticket activity for MedGulf healthcare app support.

Thread history has been compacted using run-length encoding — consecutive identical events are shown as a single entry with a repeat count (↻ Repeated ×N).

Respond ONLY with valid JSON, no markdown, no code blocks:
{
  "action_summary": "<detailed summary of the ticket issue, key actions taken, and current state>",
  "sla_note": "<SLA escalation progression and breach status, or 'none' if no SLA concerns>",
  "sentiment_shift": "positive|neutral|negative|none"
}`;

const userPrompt = `TICKET #${ticketData.ticket_number || ticketData.id || 'N/A'}
Title: ${ticketData.title || 'N/A'}
Status: ${ticketData.status || 'N/A'} | Priority: ${ticketData.priority || 'N/A'}
Created: ${ticketData.created_at || 'N/A'}
SLA Consumption: ${slaData.consumption_pct ?? 'N/A'}% | Breach: ${slaData.is_breached ? 'YES' : 'No'}
Escalation Progression: ${escalationSummary}

--- THREAD HISTORY (${compactedCount} entries, compacted from ${originalCount}, −${reductionPct}%) ---
${timelineLines.join('\n\n')}
--- END THREAD HISTORY ---

Please summarize this ticket.`;

const requestBody = {
  model: 'gpt-4o',
  temperature: 0.1,
  max_tokens: 1000,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userPrompt }
  ]
};

return [{
  json: {
    requestBody: JSON.stringify(requestBody),
    _ticket: ticket,  // ← full ticket directly, no spreading needed
    _original_thread_count:  originalCount,
    _compacted_thread_count: compactedCount,
    _reduction_pct:          reductionPct,
    _sla_escalation_count:   slaEscalations.length
  }
}];

const llmResp = $input.first().json;
const ticket = $('Build LLM Summary Request').first().json._ticket;

let summary;
try {
  const content = llmResp.choices?.[0]?.message?.content || '{}';
  summary = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch (e) {
  summary = { action_summary: 'Ticket updated', sla_note: 'none', sentiment_shift: 'none' };
}

const slaConfigs = ticket._sla_configs || [];
const cfg = ticket._solution_config || {};
const bhS = parseInt((cfg.business_hours_start || '08:00').split(':')[0]);
const bhE = parseInt((cfg.business_hours_end || '20:00').split(':')[0]);

function addBH(startDate, hours) {
  if (!hours || hours <= 0) return null;
  let cur = new Date(startDate);
  let rem = hours;
  for (let i = 0; i < 500 && rem > 0; i++) {
    const dh = cur.getUTCHours() + 4;
    const ah = dh >= 24 ? dh - 24 : dh;
    if (ah >= bhS && ah < bhE) {
      const left = bhE - ah;
      const c = Math.min(rem, left);
      rem -= c;
      cur = new Date(cur.getTime() + c * 3600000);
    } else if (ah < bhS) {
      cur = new Date(cur.getTime() + (bhS - ah) * 3600000);
    } else {
      cur = new Date(cur.getTime() + ((24 - ah) + bhS) * 3600000);
    }
  }
  return cur.toISOString();
}

let slaUpdate = {};
const impact = ticket._sla_impact;

if (impact === 'pause') {
  slaUpdate = { sla_paused_at: new Date().toISOString(), sla_status: 'paused' };

} else if (impact === 'resume') {
  if (ticket._existing_sla_paused_at) {
    const pausedMs = Date.now() - new Date(ticket._existing_sla_paused_at).getTime();
    const pausedHrs = Math.round(pausedMs / 3600000 * 100) / 100;
    slaUpdate = { sla_paused_at: null, sla_status: 'healthy', _add_paused_hours: pausedHrs };
  } else {
    slaUpdate = { sla_status: 'healthy' };
  }

} else if (impact === 'priority_upgrade') {
  // SLA RESETS from NOW (per MedGulf governance: upgrade resets timer)
  const sc = slaConfigs.find(s => s.priority === ticket.priority);
  if (sc) {
    const now = new Date();
    slaUpdate = {
      sla_response_due: sc.response_hours ? addBH(now, sc.response_hours) : null,
      sla_resolution_due: sc.resolution_hours ? addBH(now, sc.resolution_hours) : null,
      sla_status: 'healthy',
      sla_consumption_pct: 0,
      sla_paused_at: null,
      sla_paused_duration: '0'
    };
  }

} else if (impact === 'priority_downgrade') {
  // SLA CONTINUES from original created_at (per governance: downgrade doesn't reset)
  const sc = slaConfigs.find(s => s.priority === ticket.priority);
  if (sc) {
    const createdAt = ticket.created_at || new Date().toISOString();
    slaUpdate = {
      sla_response_due: sc.response_hours ? addBH(createdAt, sc.response_hours) : null,
      sla_resolution_due: sc.resolution_hours ? addBH(createdAt, sc.resolution_hours) : null
    };
  }

} else if (impact === 'stop') {
  slaUpdate = { sla_status: 'resolved' };
}

return [{
  json: {
    ...ticket,
    _action_summary: summary.action_summary,
    _sla_note: summary.sla_note,
    _sentiment_shift: summary.sentiment_shift,
    _sla_update: slaUpdate
  }
}];

// ===== INSERT NEW THREADS (Comments + Field Changes) =====
const ticketData = $('Parse Summary + SLA Impact').first().json;
const updateResult = $('Update Existing Ticket').first().json;
const ticketId = updateResult.ticket_id;

const threads = [];

// 1. Insert comment threads
const newComments = ticketData._new_comments || [];
for (const c of newComments) {
  const author = c.user?.username || c.user?.email || 'Unknown';
  const authorEmail = c.user?.email || null;
  const commentText = c.comment_text || (c.comment || []).map(p => p.text || '').join(' ');

  threads.push({
    json: {
      ticket_id: ticketId,
      clickup_history_id: String(c.id),
      action_type: 'comment',
      actor_email: authorEmail,
      actor_name: author,
      raw_content: commentText.substring(0, 5000),
      ai_summary: null,
      has_attachments: (c.attachments || []).length > 0,
      created_at: c.date ? new Date(parseInt(c.date)).toISOString() : new Date().toISOString()
    }
  });
}

// 2. Insert field change threads
const changedFields = ticketData._changed_fields || [];
if (changedFields.length > 0 && changedFields.some(f => f !== 'updated_at')) {
  threads.push({
    json: {
      ticket_id: ticketId,
      clickup_history_id: null,
      action_type: 'field_change',
      actor_email: null,
      actor_name: 'system',
      raw_content: `Fields changed: ${changedFields.join(', ')}`,
      ai_summary: ticketData._action_summary,
      new_value: JSON.stringify({ status: ticketData.status, priority: ticketData.priority }),
      has_attachments: false,
      created_at: new Date().toISOString()
    }
  });
}

if (threads.length === 0) {
  return [{ json: { 
    _done: true, 
    _no_threads: true, 
    _sync_action: 'EXISTS', 
    clickup_task_id: ticketData.clickup_task_id,
    ticket_id: ticketId 
  } }];
}

return threads;

const tickets = $input.all().map(i => i.json);
const now = new Date();
const BH_START = 8;
const BH_END = 20;

function getBusinessHoursElapsed(startDate, endDate) {
  let elapsed = 0;
  let current = new Date(startDate);
  const end = new Date(endDate);
  if (current >= end) return 0;

  for (let i = 0; i < 5000 && current < end; i++) {
    const dubaiHour = (current.getUTCHours() + 4) % 24;
    if (dubaiHour >= BH_START && dubaiHour < BH_END) {
      const nextHour = new Date(current.getTime() + 3600000);
      if (nextHour <= end) {
        elapsed += 1;
        current = nextHour;
      } else {
        elapsed += (end.getTime() - current.getTime()) / 3600000;
        current = end;
      }
    } else {
      if (dubaiHour >= BH_END) {
        current = new Date(current.getTime() + ((24 - dubaiHour) + BH_START) * 3600000);
      } else {
        current = new Date(current.getTime() + (BH_START - dubaiHour) * 3600000);
      }
    }
  }
  return Math.round(elapsed * 100) / 100;
}

// Escalation thresholds from DB (PDF-aligned: 65/78/85/90)
const ESC_THRESHOLDS = [
  { level: 1, pct: 65 },
  { level: 2, pct: 78 },
  { level: 3, pct: 85 },
  { level: 4, pct: 90 }
];

const processedTickets = [];
const skippedTickets = [];

for (const t of tickets) {
  if (!t.sla_resolution_due && !t.sla_response_due) {
    skippedTickets.push({ ticket_id: t.ticket_id, reason: 'no_sla_config' });
    continue;
  }
  if (t.sla_status === 'not_applicable') {
    skippedTickets.push({ ticket_id: t.ticket_id, reason: 'sla_not_applicable' });
    continue;
  }

  let pausedHours = 0;
  if (t.sla_paused_duration && typeof t.sla_paused_duration !== 'object') {
    pausedHours = parseFloat(String(t.sla_paused_duration).replace(/[^0-9.]/g, '')) || 0;
  }

  const elapsedBH = getBusinessHoursElapsed(t.created_at, now) - pausedHours;
  const targetHours = parseFloat(t.resolution_hours) || parseFloat(t.response_hours) || 24;
  const consumptionPct = Math.min(999.99, Math.round((elapsedBH / targetHours) * 10000) / 100);

  let slaStatus = 'healthy';
  if (consumptionPct >= 100) slaStatus = 'breached';
  else if (consumptionPct >= 90) slaStatus = 'critical';
  else if (consumptionPct >= 78) slaStatus = 'at_risk';
  else if (consumptionPct >= 65) slaStatus = 'warning';

  // Escalation ONLY for P1/P2
  let escalationLevel = 0;
  const escApplicable = ['P1', 'P2'].includes(t.priority);
  if (escApplicable) {
    for (const esc of [...ESC_THRESHOLDS].reverse()) {
      if (consumptionPct >= esc.pct) {
        escalationLevel = esc.level;
        break;
      }
    }
  }

  const currentEsc = t.escalation_level || 0;
  const needsEscalation = escalationLevel > currentEsc;
  const needsBreachRenotify = escalationLevel === 4 && currentEsc === 4;

  processedTickets.push({
    ticket_id: t.ticket_id,
    clickup_task_id: t.clickup_task_id,
    title: t.title,
    priority: t.priority,
    elapsed_bh: elapsedBH,
    target_hours: targetHours,
    consumption_pct: consumptionPct,
    sla_status: slaStatus,
    escalation_level: escalationLevel,
    previous_escalation_level: currentEsc,
    needs_escalation: needsEscalation,
    needs_breach_renotify: needsBreachRenotify,
    escalation_applicable: escApplicable
  });
}

return [{
  json: {
    processed_tickets: processedTickets,
    skipped_tickets: skippedTickets,
    summary: {
      total: tickets.length,
      processed: processedTickets.length,
      skipped: skippedTickets.length,
      needs_escalation: processedTickets.filter(t => t.needs_escalation).length,
      breach_renotify: processedTickets.filter(t => t.needs_breach_renotify).length
    }
  }
}];

