const alertResult = $input.first().json;
const recipients = $('Get Escalation Recipients').all().map(i => i.json);
const ticketData = $('Calculate SLA Consumption').first().json.processed_tickets[0];

if (!alertResult || !alertResult.id) {
  return [{ json: { _skip_notification: true } }];
}

const seenEmails = new Set();
const uniqueRecipients = recipients.filter(r => {
  if (seenEmails.has(r.email)) return false;
  seenEmails.add(r.email);
  return true;
});

const recipientNames = uniqueRecipients.map(r => r.person_name).join(', ');
const recipientUserIds = uniqueRecipients
  .filter(r => r.clickup_user_id)
  .map(r => parseInt(r.clickup_user_id));

const levelConfig = recipients[0] || {};

// Build rich text comment with proper @mentions
const commentParts = [
  { text: "⚠️ SLA ESCALATION — " + (levelConfig.level_name || 'Escalation Level ' + ticketData.escalation_level) + "\n\n" },
  { text: "Ticket: " + ticketData.title + "\n" },
  { text: "Priority: " + ticketData.priority + "\n" },
  { text: "SLA Consumption: " + ticketData.consumption_pct + "%\n" },
  { text: "Action Required: " + (levelConfig.action_description || 'Please review') + "\n" },
  { text: "Notified: " }
];

for (let i = 0; i < uniqueRecipients.length; i++) {
  const r = uniqueRecipients[i];
  if (r.clickup_user_id) {
    commentParts.push({
      type: "tag",
      user: { id: parseInt(r.clickup_user_id) }
    });
    if (i < uniqueRecipients.length - 1) {
      commentParts.push({ text: " " });
    }
  }
}

commentParts.push({ text: "\n\n⏰ This ticket requires immediate attention per SLA governance.\n\n[🧪 TEST — Please disregard this notification]" });

const commentRequestBody = JSON.stringify({
  comment: commentParts,
  notify_all: true
});

return [{
  json: {
    alert_id: alertResult.id,
    clickup_task_id: ticketData.clickup_task_id,
    ticket_id: ticketData.ticket_id,
    title: ticketData.title,
    priority: ticketData.priority,
    consumption_pct: ticketData.consumption_pct,
    escalation_level: ticketData.escalation_level,
    level_name: levelConfig.level_name || 'Escalation Level ' + ticketData.escalation_level,
    action_description: levelConfig.action_description || 'Please review',
    notified_names: recipientNames,
    notified_user_ids: recipientUserIds,
    _comment_request_body: commentRequestBody,
    _assignee_request_body: JSON.stringify({ add: recipientUserIds }),
    _skip_notification: false
  }
}];
